def find_case(case_id):
    for case in SIMULATION_CASES:
        if case['id'] == case_id:
            return case
    return None

def competency_titles():
    return [item['title'] for item in COMPETENCY_MAP]

def risk_summary():
    result = {}
    for item in RISK_LIBRARY:
        key = item['probability']
        result[key] = result.get(key, 0) + 1
    return result
